import Foundation

final class FoodDatabase: @unchecked Sendable {
    static let shared = FoodDatabase()
    private init() {}

    private let lock = NSLock()

    private lazy var _foods: [FoodItem] = {
        var all = proteins + dairy + grains + vegetables + fruits + fatsAndOils + legumes + fastFood + restaurant + beverages + snacksAndSweets + condiments + mixedDishes + supplements
        // Merge bundled expanded database (1200+ additional curated foods)
        if let url = Bundle.main.url(forResource: "expanded_foods", withExtension: "json"),
           let data = try? Data(contentsOf: url),
           let expanded = try? JSONDecoder().decode([FoodItem].self, from: data) {
            let existingNames = Set(all.map { $0.name.lowercased() })
            let newItems = expanded.filter { !existingNames.contains($0.name.lowercased()) }
            all.append(contentsOf: newItems)
        }
        return all
    }()

    var foods: [FoodItem] {
        lock.lock()
        defer { lock.unlock() }
        return _foods
    }

    /// Merge remote items into the database, adding only items whose lowercased
    /// name does not already exist. This is additive-only (no removals).
    func merge(remote: [FoodItem]) {
        lock.lock()
        let existingNames = Set(_foods.map { $0.name.lowercased() })
        let newItems = remote.filter { !existingNames.contains($0.name.lowercased()) }
        guard !newItems.isEmpty else { lock.unlock(); return }
        _foods.append(contentsOf: newItems)
        lock.unlock()
        // Invalidate RAG index so new foods are discoverable
        NutritionRAG.shared.invalidateCache()
    }

